using namespace std;

int n,c,l[10];

double dp[500][(1<<7)],t,ans;

int main()

{

    cin>>n>>c; 

    for(int i=0;i<n;++i)

    cin>>l[i];

    sort(l,l+n);

    do

    {

        memset(dp,0,sizeof(dp));

        dp[l[n-1]*n][0]=1;

        for(int i=0;i<=n*c;++i)

        for(int j=i;j<=n*c;++j)

        for(int S=0;S<(1<<n-1);++S)

            if(i%n && !((S>>(i%n-1))&1))

                dp[min(n*c,max(j,i+l[i%n-1]*n))][S|(1<<(i%n-1))]+=dp[j][S];

        ans+=dp[n*c][(1<<n-1)-1];

        t++;

    }

    while(next_permutation(l,l+n-1));

    printf("%.15lf",(double)ans/t/pow(c,n-1));

    return 0;

}

