    int N,Y;

    scanf("%d%d", &N, &Y);

    Y /= 1000;

    for (int i = 0; i <= N; i++) {

        int x = (Y - N - 4 * i) / 9;

        if ((Y - N == 9 * x + 4 * i) && (0 <= x) && (x <= N)){

            int z = N - x - i;

            if (0 <= z && z <= N) {

                printf("%d %d %d\n", x, i, z);

                return 0;

            }

        }

    }

    printf("-1 -1 -1\n");

    return 0;

}

